//! Spec-compliance tests: Tracked Changes (ISO 29500-1 §17.13)
//!
//! These tests verify our implementation against specific OOXML constructs
//! from the tracked changes specification. Tests marked `#[ignore]` document
//! known gaps — they encode the *correct* spec behavior and are expected to
//! fail against the current implementation.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use std::fs;

use stemma::{
    Alignment, BlockNode, CanonDoc, DocxRuntime, ExportMode, InlineNode, Mark, SimpleRuntime,
    TrackingStatus,
};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/tracked-changes";

/// Import a fixture and return its canonical model WITHOUT normalization.
///
/// Uses `import_docx().canonical` (which preserves pre-existing tracked changes)
/// instead of `view().canonical` (which normalizes them away via `normalize_if_needed`).
/// This is correct for spec-compliance tests that need to inspect parsed tracked
/// change constructs (rPrChange, pPrChange, block-level ins/del, etc.).
fn import_fixture(name: &str) -> (SimpleRuntime, CanonDoc) {
    let path = format!("{FIXTURES}/{name}/input.docx");
    let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));
    let runtime = SimpleRuntime::new();
    let import = runtime
        .import_docx(&bytes)
        .unwrap_or_else(|e| panic!("import {path}: {e:?}"));
    (runtime, std::sync::Arc::unwrap_or_clone(import.canonical))
}
// ── w:pPrChange ─────────────────────────────────────────────────────────

/// ISO 29500-1 §17.13.5.29: pPrChange stores previous paragraph properties.
///
/// A paragraph whose alignment was changed from left to center should expose
/// the tracked change with previous alignment information.
#[test]
fn spec_ppr_change_is_parsed() {
    let (_runtime, doc) = import_fixture("ppr-change");

    let paras = common::all_paragraphs(&doc);
    assert!(
        !paras.is_empty(),
        "document should have at least one paragraph"
    );

    let p = &paras[0];

    // Current alignment should be center
    assert_eq!(
        p.align,
        Some(Alignment::Center),
        "paragraph alignment should be Center"
    );

    // pPrChange should expose the previous alignment, author, and date.
    let change = p
        .formatting_change
        .as_ref()
        .expect("paragraph should have a formatting_change from pPrChange");

    assert_eq!(
        change.previous_alignment,
        Some(Alignment::Left),
        "previous alignment should be Left"
    );
    assert_eq!(
        change.author, "Spec Test",
        "change author should be 'Spec Test'"
    );
    assert_eq!(
        change.date.as_deref(),
        Some("2025-01-01T00:00:00Z"),
        "change date should be '2025-01-01T00:00:00Z'"
    );
}

