/// ISO 29500-1 §17.13.5.22/25: Content moved from one position to another.
///
/// The document should parse without error and preserve the moved text.
/// Move range markers (moveFromRangeStart/End, moveToRangeStart/End) should
/// be preserved as decorations.
#[test]
fn spec_tracked_moves_parse_without_error() {
    let (_runtime, doc) = import_fixture("tracked-moves");

    let paras = common::all_paragraphs(&doc);
    assert!(
        !paras.is_empty(),
        "document should have at least one paragraph"
    );

    // The moved text should appear in the paragraph content
    let all_text: String = paras[0]
        .all_inlines()
        .filter_map(|inline| match inline {
            InlineNode::Text(t) => Some(t.text.as_str()),
            _ => None,
        })
        .collect::<Vec<_>>()
        .join("");

    assert!(
        all_text.contains("moved text"),
        "paragraph should contain 'moved text', got: '{all_text}'"
    );
}

