// ── Nested tracked changes ──────────────────────────────────────────────

/// ISO 29500-1 §17.13.5.18/31: A paragraph with w:ins containing a run
/// with w:rPrChange (nested tracked changes).
///
/// The formatting change (rPrChange) should be captured even though the
/// run is inside an insertion container.
#[test]
fn spec_nested_tracked_changes_rpr_change_captured() {
    let (_runtime, doc) = import_fixture("nested-tracked");

    let paras = common::all_paragraphs(&doc);
    assert!(
        !paras.is_empty(),
        "document should have at least one paragraph"
    );

    // Find the text node from the inserted+reformatted run
    let text_nodes: Vec<_> = paras[0]
        .all_inlines()
        .filter_map(|inline| match inline {
            InlineNode::Text(t) if t.text.contains("inserted and reformatted") => Some(t),
            _ => None,
        })
        .collect();

    assert!(
        !text_nodes.is_empty(),
        "should find text 'inserted and reformatted'"
    );

    let text_node = text_nodes[0];

    // Current marks: bold + italic
    assert!(
        text_node.marks.contains(&Mark::Bold),
        "should be bold, marks: {:?}",
        text_node.marks
    );
    assert!(
        text_node.marks.contains(&Mark::Italic),
        "should be italic, marks: {:?}",
        text_node.marks
    );

    // rPrChange should be captured
    let fc = text_node
        .formatting_change
        .as_ref()
        .expect("formatting_change should be present for nested rPrChange");

    // Previous was bold only (not italic)
    assert!(
        fc.previous_marks.contains(&Mark::Bold),
        "previous marks should include Bold, got: {:?}",
        fc.previous_marks
    );
    assert!(
        !fc.previous_marks.contains(&Mark::Italic),
        "previous marks should NOT include Italic, got: {:?}",
        fc.previous_marks
    );

    assert_eq!(fc.author, "Format Author");
}

