// ── Block-level tracked insertions / deletions ──────────────────────────

/// ISO 29500-1 §17.13.5.18: Entire paragraph within w:ins at body level.
///
/// TrackedBlock.status should be Inserted for the wrapped paragraph.
#[test]
fn spec_block_level_ins_tracked() {
    let (_runtime, doc) = import_fixture("block-level-ins");

    // Find the inserted paragraph
    let inserted_block = doc
        .blocks
        .iter()
        .find(|tb| matches!(&tb.status, TrackingStatus::Inserted(_)));

    let tb = inserted_block.expect("should have a TrackedBlock with Inserted status");

    match &tb.status {
        TrackingStatus::Inserted(rev) => {
            assert_eq!(rev.revision_id, 1100);
            assert_eq!(rev.author, Some("Block Author".to_string()));
            assert_eq!(rev.date, Some("2025-07-01T16:00:00Z".to_string()));
        }
        _ => unreachable!(),
    }

    // The block content should be a paragraph containing the text
    match &tb.block {
        BlockNode::Paragraph(p) => {
            let text: String = p
                .all_inlines()
                .filter_map(|i| match i {
                    InlineNode::Text(t) => Some(t.text.as_str()),
                    _ => None,
                })
                .collect();
            assert!(
                text.contains("entire paragraph was inserted"),
                "inserted paragraph should contain the expected text, got: '{text}'"
            );
        }
        other => panic!("inserted block should be a Paragraph, got: {other:?}"),
    }
}

/// Block-level insertion should at least parse without error.
#[test]
fn spec_block_level_ins_parses_without_error() {
    let (_runtime, doc) = import_fixture("block-level-ins");

    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "document should have at least 2 paragraphs (normal + inserted), got {}",
        paras.len()
    );

    // The inserted text should appear somewhere in the document
    let all_text: String = paras
        .iter()
        .flat_map(|p| p.all_inlines())
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(t.text.as_str()),
            _ => None,
        })
        .collect::<Vec<_>>()
        .join(" ");

    assert!(
        all_text.contains("entire paragraph was inserted"),
        "inserted paragraph text should appear in document, got: '{all_text}'"
    );
}

/// ISO 29500-1 §17.13.5.14: Entire paragraph within w:del at body level.
///
/// TrackedBlock.status should be Deleted for the wrapped paragraph.
#[test]
fn spec_block_level_del_tracked() {
    let (_runtime, doc) = import_fixture("block-level-del");

    // Find the deleted paragraph
    let deleted_block = doc
        .blocks
        .iter()
        .find(|tb| matches!(&tb.status, TrackingStatus::Deleted(_)));

    let tb = deleted_block.expect("should have a TrackedBlock with Deleted status");

    match &tb.status {
        TrackingStatus::Deleted(rev) => {
            assert_eq!(rev.revision_id, 1200);
            assert_eq!(rev.author, Some("Delete Author".to_string()));
            assert_eq!(rev.date, Some("2025-08-15T10:30:00Z".to_string()));
        }
        _ => unreachable!(),
    }

    // The block content should be a paragraph containing the text
    match &tb.block {
        BlockNode::Paragraph(p) => {
            let text: String = p
                .all_inlines()
                .filter_map(|i| match i {
                    InlineNode::Text(t) => Some(t.text.as_str()),
                    _ => None,
                })
                .collect();
            assert!(
                text.contains("entire paragraph was deleted"),
                "deleted paragraph should contain the expected text, got: '{text}'"
            );
        }
        other => panic!("deleted block should be a Paragraph, got: {other:?}"),
    }
}

// ── Multiple tracked change authors ─────────────────────────────────────

/// ISO 29500-1 §17.13.5.14/18: Different changes by different authors
/// in the same paragraph.
///
/// Verify author attribution via redline_extract.
#[test]
fn spec_multi_author_tracked_changes() {
    use stemma::redline_extract::extract_redline;

    let path = format!("{FIXTURES}/multi-author/input.docx");
    let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));

    let extract = extract_redline(&bytes).expect("extract_redline should succeed");

    let all_ins = extract.all_inserted_text().join(" | ");
    let all_del = extract.all_deleted_text().join(" | ");

    assert!(
        all_ins.contains("Added by A"),
        "should find insertion by Author A, got: '{all_ins}'"
    );
    assert!(
        all_del.contains("Removed by B"),
        "should find deletion by Author B, got: '{all_del}'"
    );
}

// ── rPrChange with multiple property changes ────────────────────────────

/// ISO 29500-1 §17.13.5.31: rPrChange with multiple property changes.
///
/// Text was previously not bold with red color (FF0000). Now it is bold
/// with no color. Both previous values should be captured.
#[test]
fn spec_rpr_change_multi_props() {
    let (_runtime, doc) = import_fixture("rpr-change-multi");

    let paras = common::all_paragraphs(&doc);
    assert!(
        !paras.is_empty(),
        "document should have at least one paragraph"
    );

    let text_nodes: Vec<_> = paras[0]
        .all_inlines()
        .filter_map(|inline| match inline {
            InlineNode::Text(t) if t.text.contains("multiple formatting") => Some(t),
            _ => None,
        })
        .collect();

    assert!(
        !text_nodes.is_empty(),
        "should find text about multiple formatting"
    );

    let text_node = text_nodes[0];

    // Current formatting: bold, no color
    assert!(
        text_node.marks.contains(&Mark::Bold),
        "should currently be bold"
    );

    let fc = text_node
        .formatting_change
        .as_ref()
        .expect("formatting_change should be present");

    // Previous: not bold (Bold should NOT be in previous_marks)
    assert!(
        !fc.previous_marks.contains(&Mark::Bold),
        "previous marks should not include Bold, got: {:?}",
        fc.previous_marks
    );

    // Previous: had red color
    assert_eq!(
        fc.previous_style_props.color.as_deref(),
        Some("FF0000"),
        "previous color should be FF0000"
    );

    assert_eq!(fc.author, "Multi Prop Author");
    assert_eq!(
        fc.date.as_deref(),
        Some("2025-09-01T15:00:00Z"),
        "rPrChange date should be captured"
    );
}
